en-column{display:none!important}.reuse-data-table-wrap{max-height:calc(100vh - 365px);min-height:320px;margin:0 20px 16px;overflow:auto}.reuse-data-table{min-width:1080px}.reuse-data-table th{height:44px;padding:0 12px;white-space:nowrap;color:var(--muted);font-size:12px;font-weight:900;text-transform:uppercase}.reuse-data-table td{height:54px;white-space:nowrap}.reuse-actions{display:inline-flex;gap:5px;min-width:170px;justify-content:flex-end}.reuse-actions .icon-btn{width:30px;height:30px;border-radius:6px;background:color-mix(in srgb,currentColor 10%,var(--surface));border-color:color-mix(in srgb,currentColor 26%,var(--border))}.action-view{color:#2563eb}.action-edit{color:#f97316}.action-post{color:#16a34a}.action-cancel,.action-delete{color:#dc2626}.reuse-modal-body{display:grid;gap:14px;padding-bottom:70px}.reuse-form-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:12px}.reuse-source-note{display:flex;align-items:center;justify-content:space-between;gap:10px;padding:10px 12px;border:1px solid var(--border);border-radius:8px;background:var(--surface-soft);font-weight:800}.reuse-audit-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px}.reuse-audit-fact{padding:10px;border:1px solid var(--border);border-radius:8px;background:var(--surface-soft)}.reuse-audit-fact span{display:block;color:var(--muted);font-size:11px;font-weight:900;text-transform:uppercase}.reuse-audit-fact strong{display:block;margin-top:4px;font-size:13px;word-break:break-word}@media(max-width:900px){.reuse-card-head,.reuse-filter-row,.reuse-table-toolbar,.pagination-row{align-items:stretch;flex-direction:column}.reuse-filter-group,.reuse-filter-actions,.pager-actions,.module-actions{width:100%;flex:1 1 auto;flex-wrap:wrap}.reuse-filter-field{flex:1 1 100%;max-width:none}.reuse-filter-actions{display:grid;grid-template-columns:1fr 1fr}.reuse-filter-group .btn-erp,.pager-actions .btn-erp,.module-actions .btn-erp{width:100%}.reuse-data-table-wrap{max-height:none;min-height:0;margin-inline:12px}.reuse-form-grid,.reuse-audit-grid{grid-template-columns:1fr}}
