<script>
const endpoint='/v1/wastage-reuse',authUser=JSON.parse(localStorage.getItem('user')||'{}'),permissions=authUser.permissions||[],isSuperAdmin=authUser.role_name==='Super Admin';
const canManage=permissions.includes('wastage-reuse.manage')||isSuperAdmin,canPost=permissions.includes('wastage-reuse.post')||isSuperAdmin,canCancel=permissions.includes('wastage-reuse.cancel')||isSuperAdmin;
const columnOptions=[['reuse_no','Reuse No'],['date','Date'],['source','Wastage Item'],['consumed','Consumed'],['produced','Produced Item'],['qty','Produced Qty'],['team','Team'],['status','Status']],defaultVisibleColumns=columnOptions.map(x=>x[0]),columnStorageKey='wastageReuse.visibleColumns';
let page=1,last=1,timer,records=[],wastages=[],items=[],teams=[],locations=[],activeMode='create',activeId=null,visibleColumns=readVisibleColumns(),processing=false,paginationMeta={from:0,to:0,total:0},sortBy=sessionStorage.getItem('wastageReuse.sortBy')||'reuse_date',sortDirection=sessionStorage.getItem('wastageReuse.sortDirection')||'desc';
const esc=v=>(v??'').toString().replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m])),num=v=>Number(v||0).toLocaleString(undefined,{maximumFractionDigits:3}),opt=(rows,k,l,p)=>`<option value="">${p}</option>`+rows.map(r=>`<option value="${r[k]}">${esc(r[l]||r[k])}</option>`).join('');
function readVisibleColumns(){try{const s=JSON.parse(localStorage.getItem(columnStorageKey)||'null');if(Array.isArray(s)&&s.length)return s}catch{}return defaultVisibleColumns}
async function lookup(e,params={per_page:100}){return window.ErpApi?.cachedList ? window.ErpApi.cachedList(e,params) : (await axios.get(e,{params})).data.data.data||[]}
async function boot(){document.querySelectorAll('[data-manage-only]').forEach(el=>el.hidden=!canManage);[wastages,items,teams,locations]=await Promise.all([lookup('/v1/wastage',{per_page:100,status:'Posted'}),lookup('/v1/items'),lookup('/v1/teams'),lookup('/v1/locations')]);wastages=wastages.filter(x=>x.wastage_type==='Reusable'&&Number(x.available_qty)>0&&x.location_id);filterSourceItem.innerHTML=opt(items,'item_id','item_name','All Source Items');filterProducedItem.innerHTML=opt(items,'item_id','item_name','All Produced Items');filterTeam.innerHTML=opt(teams,'team_id','team_name','All Teams');colSourceItem.innerHTML=opt(items,'item_id','item_name','All');colProducedItem.innerHTML=opt(items,'item_id','item_name','All');colTeam.innerHTML=opt(teams,'team_id','team_name','All');renderColumnPicker();restoreState();load()}
function storeSort(){sessionStorage.setItem('wastageReuse.sortBy',sortBy);sessionStorage.setItem('wastageReuse.sortDirection',sortDirection)}
function params(){storeSort();return{page,per_page:perPage.value,search:colReuseNo.value||search.value,status:colStatus.value||filterStatus.value,date_from:colDate.value||filterDateFrom.value,date_to:filterDateTo.value,source_item_id:colSourceItem.value||filterSourceItem.value,produced_item_id:colProducedItem.value||filterProducedItem.value,team_id:colTeam.value||filterTeam.value,sort_by:sortBy,sort_direction:sortDirection}}
function clientFiltered(data){return data.filter(x=>(!colConsumedMin.value||Number(x.consumed_qty||0)>=Number(colConsumedMin.value))&&(!colProducedMin.value||Number(x.produced_qty||0)>=Number(colProducedMin.value)))}
async function load(p=page){page=p;storeState();rows.innerHTML='<tr class="skeleton-row"><td colspan="9"></td></tr>';const r=await axios.get(endpoint,{params:params()});const d=r.data.data;page=d.current_page;last=d.last_page;paginationMeta={from:d.from||0,to:d.to||0,total:d.total||0};records=clientFiltered(d.data||[]);renderRows();renderSortHeaders();renderPager()}
function badge(s){const c=s==='Posted'?'badge-success':s==='Cancelled'?'badge-danger':'badge-warning';return`<span class="badge ${c}">${esc(s)}</span>`}
function renderRows(){rows.innerHTML=records.length?records.map(x=>`<tr><td data-col="reuse_no"><strong>${esc(x.reuse_no)}</strong></td><td data-col="date">${esc(x.reuse_date)}</td><td data-col="source">${esc(x.source_item_name)}</td><td data-col="consumed" class="text-end">${num(x.consumed_qty)}</td><td data-col="produced">${esc(x.produced_item_name)}</td><td data-col="qty" class="text-end">${num(x.produced_qty)}</td><td data-col="team">${esc(x.team_name)}</td><td data-col="status">${badge(x.status)}</td><td class="text-end action-col"><span class="reuse-actions"><button class="icon-btn action-view" data-view="${x.reuse_id}" title="View"><i data-lucide="eye"></i></button>${canManage&&x.status==='Draft'?`<button class="icon-btn action-edit" data-edit="${x.reuse_id}" title="Edit"><i data-lucide="pencil"></i></button><button class="icon-btn action-delete" data-delete="${x.reuse_id}" title="Delete"><i data-lucide="trash-2"></i></button>`:''}${canPost&&x.status==='Draft'?`<button class="icon-btn action-post" data-post="${x.reuse_id}" title="Post"><i data-lucide="check-circle"></i></button>`:''}${canCancel&&x.status==='Posted'?`<button class="icon-btn action-cancel" data-cancel="${x.reuse_id}" title="Cancel"><i data-lucide="ban"></i></button>`:''}</span></td></tr>`).join(''):'<tr><td colspan="9" class="text-muted">No wastage reuse records found.</td></tr>';applyColumnVisibility();lucide?.createIcons()}
function renderSortHeaders(){document.querySelectorAll('[data-sort]').forEach(button=>{const active=button.dataset.sort===sortBy;button.classList.toggle('is-active',active);const label=button.dataset.label||button.textContent.trim();button.dataset.label=label;button.innerHTML=`${label} <i data-lucide="${active?(sortDirection==='asc'?'arrow-up':'arrow-down'):'chevrons-up-down'}"></i>`});lucide?.createIcons()}
function pageRange(){const pages=[];if(last<=7){for(let i=1;i<=last;i++)pages.push(i);return pages}pages.push(1);let start=Math.max(2,page-1),end=Math.min(last-1,page+1);if(page<=2){start=2;end=3}else if(page>=last-1){start=last-2;end=last-1}if(start>2)pages.push('...');for(let i=start;i<=end;i++)pages.push(i);if(end<last-1)pages.push('...');pages.push(last);return pages}
function renderPager(){pageLinks.innerHTML=pageRange().map(v=>v==='...'?'<span class="page-number-ellipsis">...</span>':`<button class="btn-erp btn-page-number ${Number(v)===page?'is-active':''}" type="button" data-page="${v}">${v}</button>`).join('');pageStatus.textContent=paginationMeta.total?`Showing ${paginationMeta.from} to ${paginationMeta.to} of ${paginationMeta.total} records`:'Showing 0 to 0 of 0 records';document.querySelector('[data-action="prev-page"]').disabled=page<=1;document.querySelector('[data-action="next-page"]').disabled=page>=last;lucide?.createIcons()}
function renderColumnPicker(){columnPickerMenu.innerHTML=columnOptions.map(([k,l])=>`<label><input type="checkbox" value="${k}" ${visibleColumns.includes(k)?'checked':''}><span>${l}</span></label>`).join('')}
function applyColumnVisibility(){const visible=new Set(visibleColumns);document.querySelectorAll('.reuse-data-table [data-col]').forEach(c=>c.classList.toggle('is-hidden-column',!visible.has(c.dataset.col)))}
function updateColumnVisibility(c,on){visibleColumns=on?[...new Set([...visibleColumns,c])]:visibleColumns.filter(x=>x!==c);localStorage.setItem(columnStorageKey,JSON.stringify(visibleColumns));applyColumnVisibility()}
function toggleFilterRow(){const row=document.getElementById('reuse-filter-row'),head=document.getElementById('reuse-filter-head'),button=document.querySelector('[data-action="toggle-filter-row"]'),open=row.hidden;row.hidden=!open;if(head)head.hidden=!open;button.classList.toggle('is-active',open);button.setAttribute('aria-pressed',open?'true':'false');button.title=open?'Hide filters':'Show filters'}
function storeState(){['search','filterStatus','filterDateFrom','filterDateTo','filterSourceItem','filterProducedItem','filterTeam','perPage'].forEach(k=>sessionStorage.setItem(`reuse.${k}`,window[k].value))}
function restoreState(){search.value=sessionStorage.getItem('reuse.search')||'';filterStatus.value=sessionStorage.getItem('reuse.filterStatus')||'';filterDateFrom.value=sessionStorage.getItem('reuse.filterDateFrom')||'';filterDateTo.value=sessionStorage.getItem('reuse.filterDateTo')||'';filterSourceItem.value=sessionStorage.getItem('reuse.filterSourceItem')||'';filterProducedItem.value=sessionStorage.getItem('reuse.filterProducedItem')||'';filterTeam.value=sessionStorage.getItem('reuse.filterTeam')||'';perPage.value=sessionStorage.getItem('reuse.perPage')||'10'}
function resetFilters(){[search,filterStatus,filterDateFrom,filterDateTo,filterSourceItem,filterProducedItem,filterTeam,colReuseNo,colDate,colSourceItem,colConsumedMin,colProducedItem,colProducedMin,colTeam,colStatus].forEach(el=>el.value='');perPage.value='10';sortBy='reuse_date';sortDirection='desc';load(1)}
function wastageLabel(x){return `${x.item_name||x.item_id} / ${x.location_name||''} / Avl ${num(x.available_qty)}`}
function wastageOpt(){return '<option value="">Select wastage source</option>'+wastages.map(w=>`<option value="${w.wastage_stock_id}">${esc(wastageLabel(w))}</option>`).join('')}
function selectedWastage(){return wastages.find(w=>String(w.wastage_stock_id)===String(document.getElementById('modal-source').value))}
function auditFact(l,v){return`<div class="reuse-audit-fact"><span>${l}</span><strong>${esc(v||'-')}</strong></div>`}
function modalBody(readonly=false){return`<div class="reuse-modal-body"><div class="reuse-source-note"><span id="source-note">Select reusable wastage stock</span><strong id="source-available"></strong></div><div class="reuse-form-grid"><div class="field"><i data-lucide="hash"></i><label>Reuse No</label><input id="modal-no" readonly></div><div class="field"><i data-lucide="calendar"></i><label>Date *</label><input id="modal-date" type="date" ${readonly?'disabled':''}></div><div class="field"><i data-lucide="recycle"></i><label>Wastage Source *</label><select id="modal-source" ${readonly?'disabled':''}>${wastageOpt()}</select></div><div class="field"><i data-lucide="scale"></i><label>Consumed Qty *</label><input id="modal-consumed" type="number" step="0.001" min="0.001" ${readonly?'disabled':''}></div><div class="field"><i data-lucide="package-check"></i><label>Produced Item *</label><select id="modal-produced" ${readonly?'disabled':''}>${opt(items,'item_id','item_name','Produced Item')}</select></div><div class="field"><i data-lucide="map-pin"></i><label>Destination *</label><select id="modal-destination" ${readonly?'disabled':''}>${opt(locations,'location_id','location_name','Destination')}</select></div><div class="field"><i data-lucide="users"></i><label>Team</label><select id="modal-team" ${readonly?'disabled':''}>${opt(teams,'team_id','team_name','Team')}</select></div><div class="field"><i data-lucide="scale"></i><label>Produced Qty *</label><input id="modal-produced-qty" type="number" step="0.001" min="0.001" ${readonly?'disabled':''}></div><div class="field"><i data-lucide="indian-rupee"></i><label>Cost</label><input id="modal-cost" type="number" step="0.01" min="0" ${readonly?'disabled':''}></div><div class="field" style="grid-column:1/-1"><i data-lucide="message-square"></i><label>Remarks</label><input id="modal-remarks" ${readonly?'disabled':''}></div></div><div id="modal-audit"></div><div id="modal-errors" class="form-errors" hidden></div></div>`}
function setSourceNote(){const w=selectedWastage();document.getElementById('source-note').textContent=w?`${w.item_name} from ${w.location_name||'-'}`:'Select reusable wastage stock';document.getElementById('source-available').textContent=w?`Available ${num(w.available_qty)}`:''}
async function openModal(mode,id=null){activeMode=mode;activeId=id;const readonly=mode==='view';window.ErpModal.open({title:mode==='create'?'Add Wastage Reuse':mode==='edit'?'Edit Wastage Reuse':'Display Wastage Reuse',subtitle:'Posting deducts wastage and creates recovered stock.',size:'lg',body:modalBody(readonly),footer:readonly?'<button class="btn-erp" data-modal-close><i data-lucide="x"></i> Close</button>':'<button class="btn-erp" data-modal-close><i data-lucide="x"></i> Cancel</button><button class="btn-erp btn-primary" data-action="save"><i data-lucide="save"></i> Save Draft</button>'});document.getElementById('modal-source').addEventListener('change',setSourceNote);if(mode==='create'){document.getElementById('modal-date').value=new Date().toISOString().slice(0,10);document.getElementById('modal-consumed').value=1;document.getElementById('modal-produced-qty').value=1;document.getElementById('modal-cost').value=0;const r=await axios.get(endpoint+'/next-number');document.getElementById('modal-no').value=r.data.data.reuse_no;setSourceNote();return}const r=await axios.get(`${endpoint}/${id}`),x=r.data.data;if(!wastages.find(w=>String(w.wastage_stock_id)===String(x.source_wastage_stock_id)))wastages.push({wastage_stock_id:x.source_wastage_stock_id,item_name:x.source_item_name,location_name:x.source_location_name,available_qty:x.consumed_qty});document.getElementById('modal-source').innerHTML=wastageOpt();document.getElementById('modal-no').value=x.reuse_no;document.getElementById('modal-date').value=x.reuse_date;document.getElementById('modal-source').value=x.source_wastage_stock_id;document.getElementById('modal-consumed').value=x.consumed_qty;document.getElementById('modal-produced').value=x.produced_item_id;document.getElementById('modal-destination').value=x.destination_location_id;document.getElementById('modal-team').value=x.team_id||'';document.getElementById('modal-produced-qty').value=x.produced_qty;document.getElementById('modal-cost').value=x.production_cost;document.getElementById('modal-remarks').value=x.remarks||'';document.getElementById('modal-audit').innerHTML=`<div class="reuse-audit-grid">${auditFact('Status',x.status)}${auditFact('Posted At',x.posted_at)}${auditFact('Cancelled At',x.cancelled_at)}${auditFact('Reason',x.cancellation_reason)}</div>`;setSourceNote()}
function payload(){return{reuse_no:document.getElementById('modal-no').value,reuse_date:document.getElementById('modal-date').value,source_wastage_stock_id:document.getElementById('modal-source').value,consumed_qty:document.getElementById('modal-consumed').value,produced_item_id:document.getElementById('modal-produced').value,destination_location_id:document.getElementById('modal-destination').value,team_id:document.getElementById('modal-team').value,produced_qty:document.getElementById('modal-produced-qty').value,production_cost:document.getElementById('modal-cost').value,remarks:document.getElementById('modal-remarks').value}}
async function save(){const box=document.getElementById('modal-errors');box.hidden=true;try{if(activeMode==='edit')await axios.put(`${endpoint}/${activeId}`,payload());else await axios.post(endpoint,payload());window.ErpApi?.clearLookupCache?.();window.ErpModal.close();await boot();window.ErpToast?.show('Wastage reuse saved.')}catch(e){box.textContent=e.normalizedMessage||'Unable to save reuse.';box.hidden=false}}
function confirmAction(id,type){const isCancel=type==='cancel';window.ErpModal.open({title:isCancel?'Cancel Wastage Reuse':'Post Wastage Reuse',subtitle:isCancel?'Cancellation reverses consumed and produced stock.':'Posting deducts wastage and creates recovered stock.',size:isCancel?'md':'sm',body:isCancel?'<div class="field"><i data-lucide="message-square"></i><label>Reason</label><input id="action-reason"></div><div id="action-errors" class="form-errors" hidden></div>':'<p>Post this wastage reuse entry?</p><div id="action-errors" class="form-errors" hidden></div>',footer:`<button class="btn-erp" data-modal-close><i data-lucide="x"></i> Close</button><button class="btn-erp ${isCancel?'btn-danger':'btn-primary'}" data-confirm-${type}="${id}"><i data-lucide="${isCancel?'ban':'check-circle'}"></i> ${isCancel?'Cancel Reuse':'Post'}</button>`})}
async function doAction(button,type){if(processing)return;processing=true;button.disabled=true;try{const id=button.dataset[`confirm${type[0].toUpperCase()+type.slice(1)}`];await axios.post(`${endpoint}/${id}/${type}`,{reason:document.getElementById('action-reason')?.value||''});window.ErpModal.close();await boot();window.ErpToast?.show(type==='post'?'Wastage reuse posted.':'Wastage reuse cancelled.')}catch(e){const box=document.getElementById('action-errors');if(box){box.textContent=e.normalizedMessage||'Action failed.';box.hidden=false}else window.ErpToast?.show(e.normalizedMessage||'Action failed.','danger')}finally{processing=false}}
function csvExport(){const active=columnOptions.filter(([k])=>visibleColumns.includes(k)),map={reuse_no:x=>x.reuse_no,date:x=>x.reuse_date,source:x=>x.source_item_name,consumed:x=>x.consumed_qty,produced:x=>x.produced_item_name,qty:x=>x.produced_qty,team:x=>x.team_name,status:x=>x.status};const csv=[active.map(([,l])=>`"${l}"`).join(','),...records.map(r=>active.map(([k])=>`"${String(map[k](r)??'').replaceAll('"','""')}"`).join(','))].join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'}));a.download='wastage-reuse.csv';a.click();URL.revokeObjectURL(a.href)}
document.addEventListener('DOMContentLoaded',()=>{window.perPage=per_page;window.filterDateFrom=document.getElementById('filter-date-from');window.filterDateTo=document.getElementById('filter-date-to');window.filterSourceItem=document.getElementById('filter-source-item');window.filterProducedItem=document.getElementById('filter-produced-item');window.filterTeam=document.getElementById('filter-team');window.filterStatus=document.getElementById('filter-status');window.colReuseNo=document.getElementById('col-reuse-no');window.colDate=document.getElementById('col-date');window.colSourceItem=document.getElementById('col-source-item');window.colConsumedMin=document.getElementById('col-consumed-min');window.colProducedItem=document.getElementById('col-produced-item');window.colProducedMin=document.getElementById('col-produced-min');window.colTeam=document.getElementById('col-team');window.colStatus=document.getElementById('col-status');window.pageStatus=document.getElementById('page-status');window.pageLinks=document.getElementById('page-links');window.columnPickerMenu=document.getElementById('column-picker-menu');boot();document.querySelector('[data-action="new"]').onclick=()=>openModal('create');document.querySelector('[data-action="reload"]').onclick=()=>boot();document.querySelector('[data-action="apply"]').onclick=()=>load(1);document.querySelector('[data-action="reset"]').onclick=resetFilters;document.querySelector('[data-action="toggle-filter-row"]').onclick=toggleFilterRow;document.querySelector('[data-action="clear-search"]').onclick=()=>{search.value='';load(1)};document.querySelector('[data-action="prev-page"]').onclick=()=>page>1&&load(page-1);document.querySelector('[data-action="next-page"]').onclick=()=>page<last&&load(page+1);pageLinks.addEventListener('click',e=>{const target=e.target.closest('[data-page]');if(target)load(Number(target.dataset.page))});document.querySelector('[data-action="export"]').onclick=csvExport;document.querySelector('[data-action="print"]').onclick=()=>window.print();document.querySelector('[data-action="toggle-columns"]').onclick=function(){const p=this.closest('.column-picker');p.classList.toggle('is-open');this.setAttribute('aria-expanded',p.classList.contains('is-open')?'true':'false')};columnPickerMenu.addEventListener('change',e=>{const cb=e.target.closest('input[type="checkbox"]');if(cb)updateColumnVisibility(cb.value,cb.checked)});document.querySelectorAll('[data-sort]').forEach(button=>button.addEventListener('click',function(){if(sortBy===this.dataset.sort)sortDirection=sortDirection==='asc'?'desc':'asc';else{sortBy=this.dataset.sort;sortDirection='asc'}load(1)}));[perPage,filterStatus,filterDateFrom,filterDateTo,filterSourceItem,filterProducedItem,filterTeam,colDate,colSourceItem,colProducedItem,colTeam,colStatus].forEach(el=>el.addEventListener('change',()=>load(1)));[search,colReuseNo,colConsumedMin,colProducedMin].forEach(el=>el.addEventListener('input',()=>{clearTimeout(timer);timer=setTimeout(()=>load(1),300)}));rows.addEventListener('click',async e=>{const v=e.target.closest('[data-view]')?.dataset.view,ed=e.target.closest('[data-edit]')?.dataset.edit,p=e.target.closest('[data-post]')?.dataset.post,c=e.target.closest('[data-cancel]')?.dataset.cancel,d=e.target.closest('[data-delete]')?.dataset.delete;if(v)await openModal('view',v);if(ed)await openModal('edit',ed);if(p)confirmAction(p,'post');if(c)confirmAction(c,'cancel');if(d)window.ErpModal.open({title:'Delete Wastage Reuse',subtitle:'Only draft reuse entries can be deleted.',size:'sm',body:'<p>Delete this reuse draft?</p>',footer:`<button class="btn-erp" data-modal-close><i data-lucide="x"></i> Cancel</button><button class="btn-erp btn-danger" data-confirm-delete="${d}"><i data-lucide="trash-2"></i> Delete</button>`})});document.addEventListener('click',async e=>{if(!e.target.closest('.column-picker'))document.querySelector('.column-picker')?.classList.remove('is-open');if(e.target.closest('[data-action="save"]'))await save();const p=e.target.closest('[data-confirm-post]');if(p)await doAction(p,'post');const c=e.target.closest('[data-confirm-cancel]');if(c)await doAction(c,'cancel');const d=e.target.closest('[data-confirm-delete]')?.dataset.confirmDelete;if(d){try{await axios.delete(`${endpoint}/${d}`);window.ErpModal.close();await load(page);window.ErpToast?.show('Wastage reuse deleted.')}catch(e){window.ErpToast?.show(e.normalizedMessage||'Delete failed.','danger')}}})});
</script>
@endpush
